mapper:


    /*{{mapper_namespace}}.{{select_sql_id}}*/
    SELECT
        {{grid_columns_sql}}
    FROM {{main_table}} a
    {{join_clauses}}
    WHERE 1=1
    {{search_conditions_sql}}
    ORDER BY {{order_columns}}




    /*{{mapper_namespace}}.{{detail_sql_id}}*/
    SELECT
        {{detail_columns_sql}}
    FROM {{detail_table}} a
    {{detail_join_clauses}}
    WHERE 1=1
      AND {{detail_fk_conditions}}
    ORDER BY {{detail_order_columns}}


/* OPTIONAL: upsert-onconflict block start */


    /*{{mapper_namespace}}.{{insert_sql_id}}*/
    INSERT INTO {{detail_table}} (
        {{insert_columns}},
        firs_reg_pgm_id, firs_reg_dts, firs_reg_user_id, firs_reg_ip,
        fina_reg_pgm_id, fina_reg_dts, fina_reg_user_id, fina_reg_ip
    ) VALUES (
        {{insert_values}},
        #{reg_pgm_id}, now(), #{login_user_id}, #{login_user_ip},
        #{reg_pgm_id}, now(), #{login_user_id}, #{login_user_ip}
    )
    ON CONFLICT ({{pk_columns}})
    DO UPDATE SET
        {{update_set_columns}},
        fina_reg_pgm_id = #{reg_pgm_id},
        fina_reg_dts = now(),
        fina_reg_user_id = #{login_user_id},
        fina_reg_ip = #{login_user_ip}

